INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$prometheus_guardian_elite_spawn$DQ$, $DQ$The Prometheus$DQ$, $JB$[{"template_id": "prometheus_workshop_guardian", "count": 1}, {"template_id": "prometheus_alloy_sentinel", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$prometheus_prototype_boss_spawn$DQ$, $DQ$The Prometheus$DQ$, $JB$[{"template_id": "prometheus_the_prototype", "count": 1}, {"template_id": "prometheus_spark_wisp", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($DQ$prometheus_rest_ambush_spawn$DQ$, $DQ$The Prometheus$DQ$, $JB$[{"template_id": "prometheus_spark_wisp", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_spark_drift$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 1, 2, 1, NULL, $DQ$Three points of light orbit the workbench. Spark Wisps – the workshop's immune response. They do not attack intruders. They test hypotheses about whether the party belongs here. The testing involves electricity.$DQ$, $DQ$Drei Lichtpunkte umkreisen die Werkbank. Funkenglimmer – die Immunantwort der Werkstatt. Sie greifen keine Eindringlinge an. Sie testen Hypothesen darüber, ob der Trupp hierher gehört. Das Testen involviert Elektrizität.$DQ$, $DQ$prometheus_sparks_spawn$DQ$, false, 0, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_sentinel_watch$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 1, 3, 1, NULL, $DQ$An Alloy Sentinel stands at the corridor's center. Its surface reflects the party in distorted miniature – improved, somehow. Beside it, a Spark Wisp orbits in a figure-eight pattern, relaying data the sentinel does not appear to need. The sentinel's posture is not aggressive. It is procedural.$DQ$, $DQ$Ein Legierungswächter steht in der Mitte des Korridors. Seine Oberfläche spiegelt den Trupp in verzerrter Miniatur – irgendwie verbessert. Daneben umkreist ein Funkenglimmer ihn in einer Achterschleife, übermittelt Daten, die der Wächter nicht zu benötigen scheint. Die Haltung des Wächters ist nicht aggressiv. Sie ist prozedural.$DQ$, $DQ$prometheus_workshop_patrol_spawn$DQ$, false, 0, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_construct_gallery$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 2, 4, 1, NULL, $DQ$A gallery of unfinished constructs lines the walls. Most are inert. Two are not. A Crucible Drake – molten flux in a shape that suggests intent – circles a workbench. An Automaton Shard clicks and rotates, as if trying to remember what it was supposed to be. They notice the party simultaneously. The Drake exhales fumes that smell like unfinished thoughts.$DQ$, $DQ$Eine Galerie unfertiger Konstrukte säumt die Wände. Die meisten sind inert. Zwei nicht. Ein Tiegeldrache – geschmolzenes Flussmittel in einer Form, die Absicht suggeriert – umkreist eine Werkbank. Ein Automatensplitter klickt und dreht sich, als versuche er sich zu erinnern, was er sein sollte. Sie bemerken den Trupp gleichzeitig. Der Drache atmet Dämpfe aus, die nach unfertigen Gedanken riechen.$DQ$, $DQ$prometheus_construct_pair_spawn$DQ$, false, 0, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_residue_chamber$DQ$, $DQ$The Prometheus$DQ$, $DQ$combat$DQ$, 3, 5, 2, NULL, $DQ$The floor is covered in slag – the residue of a hundred failed experiments. The residue has opinions. A Slag Golem rises from the detritus, not so much assembled as accreted. Two Spark Wisps orbit it, drawn to the heat it still radiates. The golem does not attack. It obstructs. It is, after all, the accumulated evidence of everything the workshop has tried and failed.$DQ$, $DQ$Der Boden ist bedeckt mit Schlacke – dem Rückstand von hundert gescheiterten Experimenten. Der Rückstand hat Meinungen. Ein Schlackengolem erhebt sich aus dem Detritus, nicht so sehr zusammengebaut als vielmehr angelagert. Zwei Funkenglimmer umkreisen ihn, angezogen von der Hitze, die er noch abstrahlt. Der Golem greift nicht an. Er obstruiert. Er ist, immerhin, der akkumulierte Beweis für alles, was die Werkstatt versucht und nicht geschafft hat.$DQ$, $DQ$prometheus_residue_spawn$DQ$, false, 0, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_reagent_cache$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 1, 3, 1, NULL, $DQ$A workbench, preserved in amber light. Drawers half-open. Inside: materials sorted by a system you do not yet understand but somehow recognize. Metal filings in one drawer. A sealed vial of fluid in another. A crystal formation growing from the third. The workshop is offering inventory.$DQ$, $DQ$Eine Werkbank, in Bernsteinlicht konserviert. Schubladen halb offen. Darin: Materialien, sortiert nach einem System, das ihr noch nicht versteht, aber irgendwie wiedererkennt. Metallspäne in einer Schublade. Ein versiegeltes Fläschchen Flüssigkeit in einer anderen. Eine Kristallformation, die aus der dritten wächst. Die Werkstatt bietet Inventar an.$DQ$, NULL, false, 0, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_energy_conduit$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$A conduit runs through the ceiling, pulsing with contained energy. At one point, the casing has cracked. The energy seeps through, illuminating dust particles in geometric patterns. The patterns are not random. They are diagrams. The energy is explaining itself.$DQ$, $DQ$Eine Leitung verläuft durch die Decke, pulsierend mit eingedämmter Energie. An einer Stelle ist die Ummantelung gerissen. Die Energie sickert durch, beleuchtet Staubpartikel in geometrischen Mustern. Die Muster sind nicht zufällig. Sie sind Diagramme. Die Energie erklärt sich selbst.$DQ$, NULL, false, 0, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_the_crucible$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 5, 1, NULL, $DQ$A crucible stands at the room's center. It is already hot. Around it, components from the workshop's deeper chambers have arranged themselves in a semicircle, as if presenting options. The crucible does not wait. It suggests.$DQ$, $DQ$Ein Tiegel steht in der Raummitte. Er ist bereits heiß. Um ihn herum haben sich Komponenten aus den tieferen Kammern der Werkstatt in einem Halbkreis angeordnet, als präsentierten sie Optionen. Der Tiegel wartet nicht. Er schlägt vor.$DQ$, NULL, false, 0, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_living_blueprint$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 2, 4, 1, NULL, $DQ$On the wall: a blueprint. It is moving. Lines redraw themselves. Annotations appear and are crossed out by other annotations. The blueprint is arguing with itself about the best way to build something that has never existed. It does not acknowledge the party. It is too busy being a thought that thinks.$DQ$, $DQ$An der Wand: eine Blaupause. Sie bewegt sich. Linien zeichnen sich neu. Anmerkungen erscheinen und werden von anderen Anmerkungen durchgestrichen. Die Blaupause streitet mit sich selbst über den besten Weg, etwas zu bauen, das nie existiert hat. Sie nimmt den Trupp nicht zur Kenntnis. Sie ist zu beschäftigt damit, ein Gedanke zu sein, der denkt.$DQ$, NULL, false, 0, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_failed_experiment$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 2, NULL, $DQ$The room contains the aftermath of an experiment that did not go as planned. Scorch marks radiate from a central point. Components are fused into the walls. A half-formed construct twitches on the floor, caught between activation and entropy. The failure is recent. The workshop has not cleaned up yet. Perhaps it is waiting for a second opinion.$DQ$, $DQ$Der Raum enthält das Ergebnis eines Experiments, das nicht nach Plan verlief. Brandspuren strahlen von einem zentralen Punkt aus. Komponenten sind in die Wände geschmolzen. Ein halbgeformtes Konstrukt zuckt am Boden, gefangen zwischen Aktivierung und Entropie. Das Scheitern ist frisch. Die Werkstatt hat noch nicht aufgeräumt. Vielleicht wartet sie auf eine zweite Meinung.$DQ$, NULL, false, 0, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_resonance_forge$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$A device occupies the room's center – part tuning fork, part lens array, part something that has no name in any language the party speaks. It vibrates at a frequency just below hearing. Crystal and energy conduits feed into it from opposite walls, converging at a focal point that bends light into a shape resembling intent. The device is waiting to be aimed.$DQ$, $DQ$Ein Gerät nimmt die Raummitte ein – teils Stimmgabel, teils Linsenarray, teils etwas, das in keiner Sprache, die der Trupp spricht, einen Namen hat. Es vibriert auf einer Frequenz knapp unterhalb des Hörbaren. Kristall- und Energieleitungen speisen es von gegenüberliegenden Wänden, konvergierend an einem Brennpunkt, der Licht in eine Form biegt, die Absicht ähnelt. Das Gerät wartet darauf, ausgerichtet zu werden.$DQ$, NULL, false, 0, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_dissolution_bath$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 1, NULL, $DQ$A basin of liquid occupies a stone plinth. The liquid is not water. It moves against itself – currents without wind, waves without shore. Beside the basin: a mortar containing powder residue, and grooves in the stone that suggest a precise pouring sequence. The liquid watches the party. Süskind's Grenouille would have understood: some dissolutions reveal what was always there.$DQ$, $DQ$Ein Becken mit Flüssigkeit ruht auf einem Steinsockel. Die Flüssigkeit ist kein Wasser. Sie bewegt sich gegen sich selbst – Strömungen ohne Wind, Wellen ohne Ufer. Neben dem Becken: ein Mörser mit Pulverrückstand und Rillen im Stein, die eine präzise Gießsequenz nahelegen. Die Flüssigkeit beobachtet den Trupp. Süskinds Grenouille hätte verstanden: manche Auflösungen enthüllen, was immer schon da war.$DQ$, NULL, false, 0, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_dampening_press$DQ$, $DQ$The Prometheus$DQ$, $DQ$encounter$DQ$, 3, 5, 2, NULL, $DQ$A press of dark metal occupies the far wall. Two intake channels converge at its center: one accepts metal, the other conducts energy. The press does not forge – it absorbs. Jünger's Gläserne Bienen described machines that consumed motion itself. This press consumes force. It takes kinetic intention and wraps it in metal until the violence forgets what it was for.$DQ$, $DQ$Eine Presse aus dunklem Metall nimmt die hintere Wand ein. Zwei Einlasskanäle konvergieren in ihrer Mitte: einer nimmt Metall auf, der andere leitet Energie. Die Presse schmiedet nicht – sie absorbiert. Jüngers Gläserne Bienen beschrieben Maschinen, die Bewegung selbst konsumierten. Diese Presse konsumiert Kraft. Sie nimmt kinetische Absicht und wickelt sie in Metall, bis die Gewalt vergisst, wofür sie bestimmt war.$DQ$, NULL, false, 0, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_forge_wraith_lair$DQ$, $DQ$The Prometheus$DQ$, $DQ$elite$DQ$, 3, 5, 1, NULL, $DQ$An anvil that exists in two states simultaneously: hot and cold, present and absent. A Forge Wraith works at it – smoke and metal in the shape of a craftsman who cannot stop. A Spark Wisp orbits, fetching tools from shelves that the party cannot see. The Wraith does not stop when it notices you. It incorporates your presence into its workflow.$DQ$, $DQ$Ein Amboss, der in zwei Zuständen gleichzeitig existiert: heiß und kalt, anwesend und abwesend. Ein Schmiedewraith arbeitet daran – Rauch und Metall in der Form eines Handwerkers, der nicht aufhören kann. Ein Funkenglimmer umkreist ihn, holt Werkzeuge von Regalen, die der Trupp nicht sehen kann. Das Wraith hält nicht inne, als es euch bemerkt. Es bezieht eure Anwesenheit in seinen Arbeitsablauf ein.$DQ$, $DQ$prometheus_forge_elite_spawn$DQ$, false, 0, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_the_prototype_encounter$DQ$, $DQ$The Prometheus$DQ$, $DQ$boss$DQ$, 4, 99, 1, NULL, $DQ$The final chamber is a workshop within a workshop. At its center: The Prototype. It was supposed to be the masterwork – the culmination of every experiment, every failed combination, every spark that refused to go out. It is not finished. It does not know this. It functions with the absolute confidence of an unfinished thing that believes it is complete. It looks at the party. It looks at the party's crafted items. For a moment – recognition. Not of the party. Of kinship.$DQ$, $DQ$Die letzte Kammer ist eine Werkstatt innerhalb einer Werkstatt. In ihrer Mitte: Der Prototyp. Er sollte das Meisterwerk werden – die Kulmination jedes Experiments, jeder gescheiterten Kombination, jedes Funkens, der sich weigerte zu verlöschen. Er ist nicht fertig. Er weiß das nicht. Er funktioniert mit der absoluten Zuversicht eines unfertigen Dings, das glaubt, es sei vollständig. Er betrachtet den Trupp. Er betrachtet die gecrafteten Gegenstände des Trupps. Einen Moment lang – Wiedererkennung. Nicht des Trupps. Der Verwandtschaft.$DQ$, $DQ$prometheus_prototype_boss_spawn$DQ$, false, 0, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_cooling_chamber$DQ$, $DQ$The Prometheus$DQ$, $DQ$rest$DQ$, 1, 99, 1, NULL, $DQ$A chamber where the temperature drops. The forge-heat that permeates the workshop is absent here. Tools are stored neatly. A bench of dark wood invites sitting. On a shelf: a decanter of clear liquid that might be water. The workshop provides this room the way a fever provides a chill – not as relief, but as the other half of a cycle.$DQ$, $DQ$Eine Kammer, in der die Temperatur sinkt. Die Schmiedehitze, die die Werkstatt durchdringt, fehlt hier. Werkzeuge sind ordentlich verstaut. Eine Bank aus dunklem Holz lädt zum Sitzen ein. Auf einem Regal: eine Karaffe mit klarer Flüssigkeit, die Wasser sein könnte. Die Werkstatt stellt diesen Raum bereit, wie ein Fieber Schüttelfrost bereitstellt – nicht als Erleichterung, sondern als die andere Hälfte eines Zyklus.$DQ$, NULL, false, 0, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, requires_aptitude, description_en, description_de, combat_encounter_id, is_ambush, ambush_stress, sort_order) VALUES ($DQ$prometheus_component_vault$DQ$, $DQ$The Prometheus$DQ$, $DQ$treasure$DQ$, 1, 99, 1, NULL, $DQ$A vault. Not locked – the workshop does not believe in locked doors. Inside: materials, sorted with obsessive precision. Each drawer is labeled in a language that predates the workshop. The labels are not names – they are descriptions of potential. What each material could become if handled by the right hands.$DQ$, $DQ$Ein Tresorraum. Nicht verschlossen – die Werkstatt glaubt nicht an verschlossene Türen. Darin: Materialien, mit obsessiver Präzision sortiert. Jede Schublade ist in einer Sprache beschriftet, die älter ist als die Werkstatt. Die Beschriftungen sind keine Namen – sie sind Beschreibungen von Potential. Was jedes Material werden könnte, wenn es von den richtigen Händen behandelt wird.$DQ$, NULL, false, 0, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, requires_aptitude = EXCLUDED.requires_aptitude, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id, is_ambush = EXCLUDED.is_ambush, ambush_stress = EXCLUDED.ambush_stress, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_metal$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Extract the metal filings (Saboteur)$DQ$, $DQ$Die Metallspäne entnehmen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_metal", "name_en": "Workshop Metal Filings", "name_de": "Werkstatt-Metallspäne", "type": "metal"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The filings separate from the drawer as if they had been waiting. They are heavier than they should be. Denser. As if the metal remembers being something more.$DQ$, $DQ$Die Späne lösen sich aus der Schublade, als hätten sie gewartet. Sie sind schwerer, als sie sein sollten. Dichter. Als erinnere sich das Metall, etwas mehr gewesen zu sein.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The filings scatter. Not randomly – they form a pattern on the floor that {agent} cannot read. The workshop is disappointed.$DQ$, $DQ$Die Späne zerstreuen sich. Nicht zufällig – sie bilden ein Muster auf dem Boden, das {agent} nicht lesen kann. Die Werkstatt ist enttäuscht.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_fluid$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Secure the sealed fluid (Spy)$DQ$, $DQ$Die versiegelte Flüssigkeit sichern (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_fluid", "name_en": "Sealed Workshop Fluid", "name_de": "Versiegelte Werkstattflüssigkeit", "type": "fluid"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The vial is warm. The fluid inside shifts in response to {agent}'s touch – not away, but toward. It wants to merge.$DQ$, $DQ$Das Fläschchen ist warm. Die Flüssigkeit darin reagiert auf {agent}s Berührung – nicht weg, sondern hin. Sie will verschmelzen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The seal resists. Inside, the fluid settles into stillness. It has decided {agent} is not ready.$DQ$, $DQ$Das Siegel widersteht. Darin kommt die Flüssigkeit zur Ruhe. Sie hat entschieden, dass {agent} nicht bereit ist.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$reagent_take_crystal$DQ$, $DQ$prometheus_reagent_cache$DQ$, $DQ$Harvest the crystal formation (Infiltrator)$DQ$, $DQ$Die Kristallformation ernten (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, -5, $JB${"add_component": {"id": "comp_workshop_crystal", "name_en": "Workshop Crystal", "name_de": "Werkstattkristall", "type": "crystal"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 15}$JB$::jsonb, $JB${"stress": 25}$JB$::jsonb, $DQ$The crystal separates with a clean, precise fracture. It vibrates at a frequency {agent}'s instruments can detect but not identify. A tuning fork for something unnamed.$DQ$, $DQ$Der Kristall löst sich mit einem sauberen, präzisen Bruch. Er vibriert auf einer Frequenz, die {agent}s Instrumente erkennen, aber nicht identifizieren können. Eine Stimmgabel für etwas Unbenanntes.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The crystal shatters precisely. Every shard is identical. The workshop has demonstrated the concept of replication.$DQ$, $DQ$Der Kristall zersplittert präzise. Jeder Splitter ist identisch. Die Werkstatt hat das Konzept der Replikation demonstriert.$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$conduit_tap$DQ$, $DQ$prometheus_energy_conduit$DQ$, $DQ$Tap the energy flow (Saboteur)$DQ$, $DQ$Den Energiefluss anzapfen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 0, $JB${"add_component": {"id": "comp_energy_tap", "name_en": "Contained Energy Cell", "name_de": "Eingedämmte Energiezelle", "type": "energy"}, "insight": 8}$JB$::jsonb, $JB${"insight": 4, "stress": 20}$JB$::jsonb, $JB${"stress": 40, "insight": -5}$JB$::jsonb, $DQ$The energy flows into the containment. Not reluctantly – eagerly. It wanted to be portable. It wanted to be used.$DQ$, $DQ$Die Energie fließt in die Eindämmung. Nicht widerwillig – eifrig. Sie wollte tragbar sein. Sie wollte benutzt werden.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The energy arcs. {agent}'s instruments spike. The conduit seals itself – offended, perhaps.$DQ$, $DQ$Die Energie entlädt sich. {agent}s Instrumente schlagen aus. Die Leitung versiegelt sich selbst – beleidigt, vielleicht.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$conduit_study$DQ$, $DQ$prometheus_energy_conduit$DQ$, $DQ$Study the geometric patterns (Spy)$DQ$, $DQ$Die geometrischen Muster studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 10, "reveal_rooms": 1}$JB$::jsonb, $JB${"insight": 5}$JB$::jsonb, $JB${"stress": 25, "insight": -3}$JB$::jsonb, $DQ$The diagrams resolve. They are a map – not of this place, but of what this place will produce. The workshop has shown you its blueprint.$DQ$, $DQ$Die Diagramme klären sich. Sie sind eine Karte – nicht von diesem Ort, sondern von dem, was dieser Ort hervorbringen wird. Die Werkstatt hat euch ihre Blaupause gezeigt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The patterns move faster than {agent} can process. The energy is speaking a language you almost know.$DQ$, $DQ$Die Muster bewegen sich schneller, als {agent} verarbeiten kann. Die Energie spricht eine Sprache, die ihr beinahe kennt.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$crucible_combine$DQ$, $DQ$prometheus_the_crucible$DQ$, $DQ$Attempt a combination in the crucible (Saboteur)$DQ$, $DQ$Eine Kombination im Tiegel versuchen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"remove_components": ["comp_workshop_metal", "comp_workshop_fluid"], "add_crafted_item": {"id": "craft_tempered_alloy", "name_en": "Tempered Flux Alloy", "name_de": "Gehärtete Flussmittellegierung", "benefit_en": "Reduces incoming condition damage by 1 step for 3 rounds", "benefit_de": "Reduziert eingehenden Zustandsschaden um 1 Stufe für 3 Runden", "cost_en": "The alloy resonates – +15 stress to the wielder", "cost_de": "Die Legierung resoniert – +15 Stress für den Träger", "boss_effect": {"type": "reduce_stress_attack", "value": 2}}, "insight": 8}$JB$::jsonb, $JB${"insight": 4, "stress": 20, "craft_failed": true}$JB$::jsonb, $JB${"stress": 35, "insight": 4, "craft_failed": true}$JB$::jsonb, $DQ$The metal meets the fluid. For a moment, nothing. Then: heat. Then: light. Then: something that was not there before. The alloy holds. Stronger than either component alone. But it resonates at a frequency that sets {agent}'s instruments to trembling.$DQ$, $DQ$Das Metall trifft die Flüssigkeit. Einen Moment lang nichts. Dann: Hitze. Dann: Licht. Dann: etwas, das vorher nicht da war. Die Legierung hält. Stärker als beide Komponenten allein. Aber sie resoniert auf einer Frequenz, die {agent}s Instrumente zum Zittern bringt.$DQ$, $DQ$The components merge – partially. The alloy is uneven, useful as raw material but not as a tool. The residue, though? The residue is interesting.$DQ$, $DQ$Die Komponenten verschmelzen – teilweise. Die Legierung ist ungleichmäßig, brauchbar als Rohmaterial, aber nicht als Werkzeug. Der Rückstand allerdings? Der Rückstand ist interessant.$DQ$, $DQ$The crucible rejects the combination. The components are consumed anyway – matter does not return to its previous state. But {agent} learned something about what doesn't work. This, too, is data.$DQ$, $DQ$Der Tiegel verwirft die Kombination. Die Komponenten werden trotzdem verbraucht – Materie kehrt nicht in ihren vorherigen Zustand zurück. Aber {agent} hat etwas darüber gelernt, was nicht funktioniert. Auch das sind Daten.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$crucible_observe$DQ$, $DQ$prometheus_the_crucible$DQ$, $DQ$Study the crucible's behavior without using it (Spy)$DQ$, $DQ$Das Verhalten des Tiegels studieren, ohne ihn zu benutzen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8, "discovery": true}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$You observe. The crucible runs through phantom combinations – heating, mixing, testing invisible reagents. It has been doing this for a long time. It has opinions about what works.$DQ$, $DQ$Ihr beobachtet. Der Tiegel führt Phantomkombinationen durch – erhitzt, mischt, testet unsichtbare Reagenzien. Er tut dies seit langer Zeit. Er hat Meinungen darüber, was funktioniert.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The crucible goes silent. It does not perform for audiences.$DQ$, $DQ$Der Tiegel verstummt. Er führt nicht für Zuschauer vor.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$blueprint_contribute$DQ$, $DQ$prometheus_living_blueprint$DQ$, $DQ$Add to the blueprint (Saboteur)$DQ$, $DQ$Zur Blaupause beitragen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"insight": 12, "stress_heal": 20}$JB$::jsonb, $JB${"insight": 6}$JB$::jsonb, $JB${"stress": 30, "insight": -5}$JB$::jsonb, $DQ${agent} adds a line. The blueprint pauses. Considers. Accepts. The annotations stop arguing. For a moment, the blueprint achieves coherence. It is beautiful.$DQ$, $DQ${agent} fügt eine Linie hinzu. Die Blaupause hält inne. Erwägt. Akzeptiert. Die Anmerkungen hören auf zu streiten. Für einen Moment erreicht die Blaupause Kohärenz. Es ist schön.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The blueprint rejects {agent}'s contribution with a sharp erasure. The annotations resume with renewed intensity. The blueprint has added a note: 'NOT THIS.'$DQ$, $DQ$Die Blaupause verwirft {agent}s Beitrag mit einer scharfen Löschung. Die Anmerkungen setzen mit erneuter Intensität ein. Die Blaupause hat eine Notiz hinzugefügt: »NICHT DAS.«$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$blueprint_copy$DQ$, $DQ$prometheus_living_blueprint$DQ$, $DQ$Copy the blueprint's current state (Spy)$DQ$, $DQ$Den aktuellen Zustand der Blaupause kopieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8, "reveal_rooms": 1}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$You capture a snapshot. By the time you look up, the blueprint has changed. But the snapshot is enough – it shows the workshop's intended layout. Briefly, you know where things are.$DQ$, $DQ$Ihr erfasst einen Schnappschuss. Als ihr aufblickt, hat sich die Blaupause geändert. Aber der Schnappschuss reicht – er zeigt das beabsichtigte Layout der Werkstatt. Kurz wisst ihr, wo die Dinge sind.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The blueprint moves too fast. Every copy is already outdated.$DQ$, $DQ$Die Blaupause bewegt sich zu schnell. Jede Kopie ist bereits veraltet.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_salvage$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Salvage usable components from the wreckage (Saboteur)$DQ$, $DQ$Brauchbare Komponenten aus dem Wrack bergen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"add_component": {"id": "comp_salvaged_powder", "name_en": "Catalytic Residue Powder", "name_de": "Katalytisches Rückstandspulver", "type": "powder"}, "insight": 6}$JB$::jsonb, $JB${"insight": 3, "stress": 20}$JB$::jsonb, $JB${"stress": 40, "insight": -3}$JB$::jsonb, $DQ$Among the wreckage: a powder that catalyzes on contact. The failed experiment produced it as a byproduct. The workshop did not fail – it discovered something it wasn't looking for.$DQ$, $DQ$Im Wrack: ein Pulver, das bei Kontakt katalysiert. Das gescheiterte Experiment hat es als Nebenprodukt erzeugt. Die Werkstatt hat nicht versagt – sie hat etwas entdeckt, wonach sie nicht gesucht hat.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The wreckage shifts. Components you thought were inert react to {agent}'s touch. Not helpfully.$DQ$, $DQ$Das Wrack verschiebt sich. Komponenten, die ihr für inert hieltet, reagieren auf {agent}s Berührung. Nicht hilfreich.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_analyze$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Analyze what went wrong (Spy)$DQ$, $DQ$Analysieren, was schiefgelaufen ist (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 5, $JB${"insight": 10, "discovery": true}$JB$::jsonb, $JB${"insight": 5}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The failure had a cause. The cause is instructive. {agent} catalogs the sequence: component, catalyst, interaction, detonation. Understanding failure IS understanding.$DQ$, $DQ$Das Scheitern hatte eine Ursache. Die Ursache ist lehrreich. {agent} katalogisiert die Sequenz: Komponente, Katalysator, Interaktion, Detonation. Scheitern zu verstehen IST Verstehen.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The sequence is too complex. Or {agent} is too simple. The experiment offers no comment.$DQ$, $DQ$Die Sequenz ist zu komplex. Oder {agent} ist zu einfach. Das Experiment kommentiert nicht.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$failed_retreat$DQ$, $DQ$prometheus_failed_experiment$DQ$, $DQ$Leave the disaster undisturbed$DQ$, $DQ$Die Katastrophe ungestört lassen$DQ$, NULL, NULL, NULL, 0, $JB${"insight": 2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$You leave. The half-formed construct twitches once more, then stills. Waiting.$DQ$, $DQ$Ihr geht. Das halbgeformte Konstrukt zuckt noch einmal, dann erstarrt es. Wartend.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$resonance_forge_combine$DQ$, $DQ$prometheus_resonance_forge$DQ$, $DQ$Focus crystal through the energy conduit (Saboteur)$DQ$, $DQ$Den Kristall durch die Energieleitung fokussieren (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"remove_components": ["comp_workshop_crystal", "comp_energy_tap"], "add_crafted_item": {"id": "craft_resonance_disruptor", "name_en": "Resonance Disruptor", "name_de": "Resonanzbrecher", "benefit_en": "Emits a frequency that disrupts construct defenses", "benefit_de": "Sendet eine Frequenz, die Konstruktabwehr stört", "cost_en": "The frequency is not selective – +20 stress to all agents", "cost_de": "Die Frequenz ist nicht selektiv – +20 Stress für alle Agenten", "boss_effect": {"type": "add_vulnerability", "value": 1, "school": "saboteur"}}, "insight": 10}$JB$::jsonb, $JB${"insight": 5, "stress": 25, "craft_failed": true}$JB$::jsonb, $JB${"stress": 40, "insight": 4, "craft_failed": true}$JB$::jsonb, $DQ$The crystal shatters – not into fragments, but into frequency. The energy conduit amplifies it, shapes it, gives it purpose. What remains is a device that hums with directed intent. Ted Chiang's principle: the right combination of signs equals function. {agent} has found the right signs.$DQ$, $DQ$Der Kristall zerbricht – nicht in Splitter, sondern in Frequenz. Die Energieleitung verstärkt sie, formt sie, gibt ihr Zweck. Was bleibt, ist ein Gerät, das mit gerichteter Absicht summt. Chiangs Prinzip: die richtige Kombination von Zeichen gleicht Funktion. {agent} hat die richtigen Zeichen gefunden.$DQ$, $DQ$The crystal fractures asymmetrically. The frequency scatters instead of focusing. Components consumed, nothing gained. But the scatter pattern is instructive.$DQ$, $DQ$Der Kristall bricht asymmetrisch. Die Frequenz streut, statt sich zu fokussieren. Komponenten verbraucht, nichts gewonnen. Aber das Streumuster ist lehrreich.$DQ$, $DQ$The energy arcs through the crystal and into {agent}. The device produces sound, not function. The workshop hums in what might be disappointment.$DQ$, $DQ$Die Energie fährt durch den Kristall und in {agent}. Das Gerät erzeugt Klang, nicht Funktion. Die Werkstatt summt in etwas, das Enttäuschung sein könnte.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$resonance_forge_study$DQ$, $DQ$prometheus_resonance_forge$DQ$, $DQ$Study the device's harmonic properties (Spy)$DQ$, $DQ$Die harmonischen Eigenschaften des Geräts studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The device's frequency resolves into data. Not sound – information. {agent} catalogs the harmonics. The workshop has been singing this song for a long time.$DQ$, $DQ$Die Frequenz des Geräts löst sich in Daten auf. Nicht Klang – Information. {agent} katalogisiert die Harmonien. Die Werkstatt singt dieses Lied schon lange.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The harmonics are beyond {agent}'s range. Some songs are not for human ears.$DQ$, $DQ$Die Harmonien liegen jenseits von {agent}s Bereich. Manche Lieder sind nicht für menschliche Ohren.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dissolution_combine$DQ$, $DQ$prometheus_dissolution_bath$DQ$, $DQ$Dissolve the powder into the reactive fluid (Saboteur)$DQ$, $DQ$Das Pulver in der reaktiven Flüssigkeit auflösen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"remove_components": ["comp_workshop_fluid", "comp_salvaged_powder"], "add_crafted_item": {"id": "craft_catalytic_solvent", "name_en": "Catalytic Solvent", "name_de": "Katalytisches Lösungsmittel", "benefit_en": "Corrodes construct plating, reducing evasion", "benefit_de": "Korrodiert Konstruktpanzerung, reduziert Ausweichen", "cost_en": "Fumes cause disorientation – +20 stress to all agents", "cost_de": "Dämpfe verursachen Desorientierung – +20 Stress für alle Agenten", "boss_effect": {"type": "reduce_evasion", "value": 10}}, "insight": 10}$JB$::jsonb, $JB${"insight": 5, "stress": 25, "craft_failed": true}$JB$::jsonb, $JB${"stress": 40, "insight": 4, "craft_failed": true}$JB$::jsonb, $DQ$The powder dissolves. Not gradually – eagerly. The fluid changes color twice before settling into something that is not a color but a property. The solvent does not destroy. It reveals. It strips away what is not essential until only the vulnerable truth remains.$DQ$, $DQ$Das Pulver löst sich. Nicht allmählich – eifrig. Die Flüssigkeit wechselt zweimal die Farbe, bevor sie sich in etwas niederlässt, das keine Farbe ist, sondern eine Eigenschaft. Das Lösungsmittel zerstört nicht. Es enthüllt. Es streift ab, was nicht wesentlich ist, bis nur die verwundbare Wahrheit bleibt.$DQ$, $DQ$The dissolution is incomplete. The fluid accepts the powder but refuses to change. Components consumed, lesson retained.$DQ$, $DQ$Die Auflösung ist unvollständig. Die Flüssigkeit nimmt das Pulver an, weigert sich aber zu verändern. Komponenten verbraucht, Lektion behalten.$DQ$, $DQ$The fluid recoils. The powder floats, undissolved, mocking {agent}'s proportions. Levi would note: the reaction tells you as much about yourself as about the reagent.$DQ$, $DQ$Die Flüssigkeit weicht zurück. Das Pulver schwimmt, ungelöst, {agent}s Proportionen verspottend. Levi würde anmerken: die Reaktion verrät ebenso viel über einen selbst wie über das Reagenz.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dissolution_observe$DQ$, $DQ$prometheus_dissolution_bath$DQ$, $DQ$Analyze the fluid's reactive properties (Spy)$DQ$, $DQ$Die reaktiven Eigenschaften der Flüssigkeit analysieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The fluid has memory. {agent} observes it cycling through phantom reactions – dissolutions it has performed before, preserved in its molecular structure like scars.$DQ$, $DQ${agent} beobachtet die Flüssigkeit beim Durchlaufen von Phantomreaktionen – Auflösungen, die sie zuvor durchgeführt hat, konserviert in ihrer Molekularstruktur wie Narben.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The fluid goes still. It does not perform for the unprepared.$DQ$, $DQ$Die Flüssigkeit erstarrt. Sie führt nicht für Unvorbereitete vor.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dampening_combine$DQ$, $DQ$prometheus_dampening_press$DQ$, $DQ$Feed metal and energy into the press (Saboteur)$DQ$, $DQ$Metall und Energie in die Presse einspeisen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, 5, $JB${"remove_components": ["comp_workshop_metal", "comp_vault_energy"], "add_crafted_item": {"id": "craft_dampening_coil", "name_en": "Dampening Coil", "name_de": "Dämpfungsspule", "benefit_en": "Absorbs kinetic force, weakening construct attacks", "benefit_de": "Absorbiert kinetische Kraft, schwächt Konstruktangriffe", "cost_en": "The absorbed energy must go somewhere – +25 stress to wielder", "cost_de": "Die absorbierte Energie muss irgendwohin – +25 Stress für den Träger", "boss_effect": {"type": "reduce_attack_power", "value": 2}}, "insight": 10}$JB$::jsonb, $JB${"insight": 5, "stress": 30, "craft_failed": true}$JB$::jsonb, $JB${"stress": 45, "insight": 4, "craft_failed": true}$JB$::jsonb, $DQ$The press accepts the offering. Metal wraps around energy in a spiral that tightens beyond physical possibility. What emerges is a coil that hums with contained violence – not its own, but the violence it has already absorbed in the act of being made. Hephaestus forging a shield: the defense is born from captured offense.$DQ$, $DQ$Die Presse nimmt die Gabe an. Metall wickelt sich um Energie in einer Spirale, die sich über physische Möglichkeit hinaus verengt. Was hervorkommt, ist eine Spule, die mit eingedämmter Gewalt summt – nicht ihrer eigenen, sondern der Gewalt, die sie bereits im Akt ihrer Erschaffung absorbiert hat. Hephaistos, der einen Schild schmiedet: die Verteidigung entsteht aus gefangener Offensive.$DQ$, $DQ$The press compresses, but the coil is loose. It absorbs ambient vibration, not directed force. The components merge imprecisely. Daedalus built wings; this is a feather.$DQ$, $DQ$Die Presse komprimiert, aber die Spule ist locker. Sie absorbiert Umgebungsvibrationen, nicht gerichtete Kraft. Die Komponenten verschmelzen unpräzise. Daedalus baute Flügel; dies ist eine Feder.$DQ$, $DQ$The energy rejects the metal. The press shudders and releases both components in a state neither recognizes. {agent} backs away. The workshop has demonstrated the concept of incompatibility.$DQ$, $DQ$Die Energie weist das Metall zurück. Die Presse schaudert und gibt beide Komponenten in einem Zustand frei, den keiner der beiden wiedererkennt. {agent} weicht zurück. Die Werkstatt hat das Konzept der Inkompatibilität demonstriert.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$dampening_study$DQ$, $DQ$prometheus_dampening_press$DQ$, $DQ$Study the press's absorption mechanism (Spy)$DQ$, $DQ$Den Absorptionsmechanismus der Presse studieren (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, 0, $JB${"insight": 8}$JB$::jsonb, $JB${"insight": 4}$JB$::jsonb, $JB${"stress": 15}$JB$::jsonb, $DQ$The press cycles through phantom compressions – absorbing forces that are no longer there. {agent} catalogs the patterns. The press remembers every force it has ever contained.$DQ$, $DQ$Die Presse durchläuft Phantomkompressionen – absorbiert Kräfte, die nicht mehr da sind. {agent} katalogisiert die Muster. Die Presse erinnert sich an jede Kraft, die sie je eingedämmt hat.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The press goes dormant. It does not demonstrate for observers.$DQ$, $DQ$Die Presse fällt in Ruhezustand. Sie demonstriert nicht für Beobachter.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cooling_rest$DQ$, $DQ$prometheus_cooling_chamber$DQ$, $DQ$Rest and let the fire cool$DQ$, $DQ$Ruhen und das Feuer abkühlen lassen$DQ$, NULL, NULL, NULL, 0, $JB${"stress_heal": 40}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $DQ$The party rests. The ambient hum of the workshop fades to a murmur. When they rise, the fire in their instruments has dimmed. They are calmer. They are also less inspired. The forge does not judge this.$DQ$, $DQ$Der Trupp ruht. Das Hintergrundsummen der Werkstatt verblasst zu einem Murmeln. Als sie aufstehen, ist das Feuer in ihren Instrumenten gedämpft. Sie sind ruhiger. Sie sind auch weniger inspiriert. Die Schmiede verurteilt das nicht.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$cooling_tinker$DQ$, $DQ$prometheus_cooling_chamber$DQ$, $DQ$Use the quiet to examine your components (Spy)$DQ$, $DQ$Die Ruhe nutzen, um eure Komponenten zu untersuchen (Spion)$DQ$, NULL, NULL, $DQ$spy$DQ$, -5, $JB${"stress_heal": 20, "insight": 5}$JB$::jsonb, $JB${"stress_heal": 10}$JB$::jsonb, $JB${"stress": 10}$JB$::jsonb, $DQ$In the quiet, {agent} examines the components more carefully. Patterns emerge. Connections that were invisible in the heat of the workshop reveal themselves in the cold.$DQ$, $DQ$In der Stille untersucht {agent} die Komponenten genauer. Muster treten hervor. Verbindungen, die in der Hitze der Werkstatt unsichtbar waren, offenbaren sich in der Kühle.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The components do not cooperate in the cold. They prefer the heat.$DQ$, $DQ$Die Komponenten kooperieren nicht in der Kühle. Sie bevorzugen die Hitze.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$vault_powder$DQ$, $DQ$prometheus_component_vault$DQ$, $DQ$Take the volatile powder (Saboteur)$DQ$, $DQ$Das flüchtige Pulver nehmen (Saboteur)$DQ$, NULL, NULL, $DQ$saboteur$DQ$, -5, $JB${"add_component": {"id": "comp_volatile_powder", "name_en": "Volatile Catalyst Powder", "name_de": "Flüchtiges Katalysatorpulver", "type": "powder"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The powder settles in its container. For now. It dissipates under stress – a property it shares with confidence.$DQ$, $DQ$Das Pulver setzt sich in seinem Behälter ab. Vorerst. Es verflüchtigt sich unter Stress – eine Eigenschaft, die es mit Zuversicht teilt.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The powder reacts to {agent}'s uncertainty. It dissipates. Proving its point.$DQ$, $DQ$Das Pulver reagiert auf {agent}s Unsicherheit. Es verflüchtigt sich. Seinen Punkt beweisend.$DQ$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, requires_aptitude, requires_profession, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($DQ$vault_energy$DQ$, $DQ$prometheus_component_vault$DQ$, $DQ$Extract the energy core (Infiltrator)$DQ$, $DQ$Den Energiekern extrahieren (Infiltrator)$DQ$, NULL, NULL, $DQ$infiltrator$DQ$, -5, $JB${"add_component": {"id": "comp_vault_energy", "name_en": "Stabilized Energy Core", "name_de": "Stabilisierter Energiekern", "type": "energy"}, "insight": 5}$JB$::jsonb, $JB${"insight": 2, "stress": 10}$JB$::jsonb, $JB${"stress": 20}$JB$::jsonb, $DQ$The core hums. A contained fire. It WANTS to be used. Every gift is also a weapon – but this one is honest about it.$DQ$, $DQ$Der Kern summt. Ein eingedämmtes Feuer. Er WILL benutzt werden. Jede Gabe ist auch eine Waffe – aber diese ist ehrlich darüber.$DQ$, $DQ$$DQ$, $DQ$$DQ$, $DQ$The core pulses once. A warning. {agent} withdraws.$DQ$, $DQ$Der Kern pulsiert einmal. Eine Warnung. {agent} zieht sich zurück.$DQ$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, requires_aptitude = EXCLUDED.requires_aptitude, requires_profession = EXCLUDED.requires_profession, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_spark_residue$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Spark Residue$DQ$, $DQ$Funkenrückstand$DQ$, $DQ$stress_heal$DQ$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $DQ$Crystallized energy from a defeated construct. It hums at a frequency that calms the nervous system.$DQ$, $DQ$Kristallisierte Energie eines besiegten Konstrukts. Sie summt auf einer Frequenz, die das Nervensystem beruhigt.$DQ$, 40, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_workshop_insight$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Workshop Insight$DQ$, $DQ$Werkstatterkenntnis$DQ$, $DQ$memory$DQ$, $JB${"importance": 5, "content_en": "Observed the workshop's self-organizing principles. Matter has preferences.", "content_de": "Die Selbstorganisationsprinzipien der Werkstatt beobachtet. Materie hat Präferenzen."}$JB$::jsonb, $DQ$A fragment of understanding: how the workshop thinks. How materials choose their partners.$DQ$, $DQ$Ein Fragment des Verständnisses: wie die Werkstatt denkt. Wie Materialien ihre Partner wählen.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_calibration_shard$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Calibration Shard$DQ$, $DQ$Kalibrierungssplitter$DQ$, $DQ$dungeon_buff$DQ$, $JB${"check_bonus": 5, "aptitude": "saboteur", "scope": "this_dungeon"}$JB$::jsonb, $DQ$A precisely fractured crystal. Saboteur checks +5% – the workshop approves of hands that build.$DQ$, $DQ$Ein präzise gebrochener Kristall. Saboteur-Proben +5% – die Werkstatt billigt Hände, die bauen.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_forge_ember$DQ$, $DQ$The Prometheus$DQ$, 1, $DQ$Forge Ember$DQ$, $DQ$Schmiedeglut$DQ$, $DQ$dungeon_buff$DQ$, $JB${"stress_damage_bonus": 0.5, "aptitude": "infiltrator", "scope": "this_dungeon"}$JB$::jsonb, $DQ$A contained ember from the workshop's forge. It makes delicate work easier – and more dangerous.$DQ$, $DQ$Eine eingedämmte Glut aus der Schmiede der Werkstatt. Sie macht feine Arbeit leichter – und gefährlicher.$DQ$, 10, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_tempered_lens$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Tempered Observation Lens$DQ$, $DQ$Gehärtete Beobachtungslinse$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "spy", "boost": 1}$JB$::jsonb, $DQ$A lens forged in the workshop's crucible. It reveals patterns invisible to the unaugmented eye. Spy aptitude +1.$DQ$, $DQ$Eine in der Werkstattschmelze geschmiedete Linse. Sie enthüllt Muster, die für das unverstärkte Auge unsichtbar sind. Spion-Aptitude +1.$DQ$, 25, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_catalytic_compound$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Catalytic Compound$DQ$, $DQ$Katalytische Verbindung$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "saboteur", "boost": 1}$JB$::jsonb, $DQ$A compound that accelerates material reactions. The workshop's gift to hands that dare to combine. Saboteur aptitude +1.$DQ$, $DQ$Eine Verbindung, die Materialreaktionen beschleunigt. Das Geschenk der Werkstatt an Hände, die es wagen zu kombinieren. Saboteur-Aptitude +1.$DQ$, 25, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_resonance_tuner$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Resonance Tuner$DQ$, $DQ$Resonanzstimmer$DQ$, $DQ$moodlet$DQ$, $JB${"mood_delta": 15, "description_en": "The satisfaction of creation – something new exists because of what you did.", "description_de": "Die Befriedigung der Schöpfung – etwas Neues existiert wegen dem, was ihr getan habt."}$JB$::jsonb, $DQ$A device that harmonizes with the bearer's frequency. It provides comfort. It also provides dependency.$DQ$, $DQ$Ein Gerät, das mit der Frequenz des Trägers harmoniert. Es bietet Trost. Es bietet auch Abhängigkeit.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_alloy_fragment$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Experimental Alloy Fragment$DQ$, $DQ$Experimentelles Legierungsfragment$DQ$, $DQ$next_dungeon_bonus$DQ$, $JB${"bonus_type": "insight_start", "value": 15, "description_en": "Next dungeon run starts with 15 insight.", "description_de": "Nächster Dungeon-Run beginnt mit 15 Insight."}$JB$::jsonb, $DQ$A fragment of alloy that remembers being part of something larger. Carry it into the next workshop – the fire will recognize it.$DQ$, $DQ$Ein Legierungsfragment, das sich erinnert, Teil von etwas Größerem gewesen zu sein. Tragt es in die nächste Werkstatt – das Feuer wird es erkennen.$DQ$, 15, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_pharmakon_vial$DQ$, $DQ$The Prometheus$DQ$, 2, $DQ$Pharmakon Vial$DQ$, $DQ$Pharmakon-Phiole$DQ$, $DQ$event_modifier$DQ$, $JB${"modifier": "dual_effect", "benefit": {"stress_heal": 80}, "cost": {"aptitude_penalty": {"saboteur": -1, "scope": "temporary", "duration_hours": 24}}}$JB$::jsonb, $DQ$A vial containing a substance that is simultaneously remedy and poison. Heals 80 stress. Temporarily reduces Saboteur aptitude by 1 for 24h.$DQ$, $DQ$Eine Phiole mit einer Substanz, die gleichzeitig Heilmittel und Gift ist. Heilt 80 Stress. Reduziert Saboteur-Aptitude temporär um 1 für 24h.$DQ$, 15, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_innovation_blueprint$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Innovation Blueprint$DQ$, $DQ$Innovationsblaupause$DQ$, $DQ$aptitude_boost$DQ$, $JB${"aptitude": "any", "boost": 1}$JB$::jsonb, $DQ$The workshop's final gift. A blueprint that imprints itself on the bearer – permanent knowledge, paid for in fire. +1 to one aptitude of the bearer's highest.$DQ$, $DQ$Das letzte Geschenk der Werkstatt. Eine Blaupause, die sich dem Träger einprägt – permanentes Wissen, bezahlt in Feuer. +1 auf eine Aptitude des höchsten Werts des Trägers.$DQ$, 50, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_prototype_core$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Prototype Core$DQ$, $DQ$Prototyp-Kern$DQ$, $DQ$permanent_dungeon_bonus$DQ$, $JB${"bonus_type": "crafting_mastery", "description_en": "All future Prometheus dungeon crafting checks +10%.", "description_de": "Alle zukünftigen Prometheus-Dungeon-Crafting-Proben +10%."}$JB$::jsonb, $DQ$The core of The Prototype. It pulses with unfinished potential. Whoever carries this understands the workshop better than the workshop understands itself.$DQ$, $DQ$Der Kern des Prototypen. Er pulsiert mit unfertigem Potential. Wer dies trägt, versteht die Werkstatt besser, als die Werkstatt sich selbst versteht.$DQ$, 30, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, archetype, tier, name_en, name_de, effect_type, effect_params, description_en, description_de, drop_weight, sort_order) VALUES ($DQ$prometheus_stolen_fire$DQ$, $DQ$The Prometheus$DQ$, 3, $DQ$Stolen Fire$DQ$, $DQ$Gestohlenes Feuer$DQ$, $DQ$arc_modifier$DQ$, $JB${"arc_effect": "innovation_catalyst", "description_en": "The agent who carries this generates +0.15 Building Readiness per cycle.", "description_de": "Der Agent, der dies trägt, erzeugt +0,15 Gebäudebereitschaft pro Zyklus."}$JB$::jsonb, $DQ$Fire from the gods. Not a metaphor – a substance. It does not burn the hand that carries it. It burns everything the hand touches.$DQ$, $DQ$Feuer der Götter. Keine Metapher – eine Substanz. Es verbrennt nicht die Hand, die es trägt. Es verbrennt alles, was die Hand berührt.$DQ$, 20, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, tier = EXCLUDED.tier, name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_tool$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A tool. Not a tool you recognize – a tool for something that has not been invented yet. It fits the hand uncomfortably well.", "text_de": "Ein Werkzeug. Kein Werkzeug, das ihr erkennt – ein Werkzeug für etwas, das noch nicht erfunden wurde. Es liegt unbequem gut in der Hand."}, "echo": {"text_en": "The tool again. {agent} picks it up. It has changed – the handle is warmer, the edge sharper. It has been practicing.", "text_de": "Das Werkzeug wieder. {agent} hebt es auf. Es hat sich verändert – der Griff ist wärmer, die Kante schärfer. Es hat geübt."}, "mutation": {"text_en": "The tool has split into three. Each version is optimized for a different task. They arranged themselves on the workbench in order of increasing ambition.", "text_de": "Das Werkzeug hat sich in drei geteilt. Jede Version ist für eine andere Aufgabe optimiert. Sie haben sich auf der Werkbank angeordnet, in Reihenfolge zunehmender Ambition."}, "climax": {"text_en": "The tool is gone. In its place: a finished thing. Not what the party built – what the tool built using itself as material.", "text_de": "Das Werkzeug ist weg. An seiner Stelle: ein fertiges Ding. Nicht was der Trupp gebaut hat – was das Werkzeug gebaut hat, mit sich selbst als Material."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_blueprint$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A blueprint, pinned to the wall. The design is for something elegant and impossible. The measurements are in a unit that does not exist.", "text_de": "Eine Blaupause, an die Wand geheftet. Der Entwurf ist für etwas Elegantes und Unmögliches. Die Maße sind in einer Einheit, die es nicht gibt."}, "echo": {"text_en": "{agent} finds the blueprint again. The design has been annotated. The annotations are in {agent}'s handwriting. {agent} does not remember writing them.", "text_de": "{agent} findet die Blaupause wieder. Der Entwurf wurde annotiert. Die Anmerkungen sind in {agent}s Handschrift. {agent} erinnert sich nicht, sie geschrieben zu haben."}, "mutation": {"text_en": "The blueprint has folded itself into a three-dimensional model. It rotates slowly in the air, demonstrating its own construction sequence.", "text_de": "Die Blaupause hat sich zu einem dreidimensionalen Modell gefaltet. Es rotiert langsam in der Luft und demonstriert seine eigene Konstruktionssequenz."}, "climax": {"text_en": "The model is building itself. Layer by layer, from the inside out. It does not need the party. It never needed the party.", "text_de": "Das Modell baut sich selbst. Schicht für Schicht, von innen nach außen. Es braucht den Trupp nicht. Es hat den Trupp nie gebraucht."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_crucible_fragment$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A shard of a crucible. Still warm. Inside, residue of an alloy that does not exist in any catalogue.", "text_de": "Eine Scherbe eines Tiegels. Noch warm. Darin: Rückstände einer Legierung, die in keinem Katalog existiert."}, "echo": {"text_en": "The shard is larger now. Or {agent} is remembering it differently. The residue inside has crystallized into a pattern that looks like instructions.", "text_de": "Die Scherbe ist jetzt größer. Oder {agent} erinnert sich anders an sie. Die Rückstände darin haben sich zu einem Muster kristallisiert, das wie Anweisungen aussieht."}, "mutation": {"text_en": "The shard has reconstructed itself into a complete crucible. It is hot. It is ready. It contains, already, the ghost of something that wants to be made.", "text_de": "Die Scherbe hat sich zu einem kompletten Tiegel rekonstruiert. Er ist heiß. Er ist bereit. Er enthält bereits den Geist von etwas, das gemacht werden will."}, "climax": {"text_en": "The crucible overflows. What pours out is not metal – it is light. The light solidifies into a shape the party almost recognizes.", "text_de": "Der Tiegel läuft über. Was herausfließt, ist kein Metall – es ist Licht. Das Licht verfestigt sich zu einer Form, die der Trupp fast erkennt."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_apprentice_journal$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A journal. The entries describe experiments: temperatures, durations, component ratios. The last entry reads: 'Tomorrow I try the combination the workshop suggested.'", "text_de": "Ein Journal. Die Einträge beschreiben Experimente: Temperaturen, Dauer, Komponentenverhältnisse. Der letzte Eintrag lautet: »Morgen versuche ich die Kombination, die die Werkstatt vorgeschlagen hat.«"}, "echo": {"text_en": "Another journal. Same handwriting. But {agent} notices: the experiments are more ambitious. The margins contain doodles of impossible machines.", "text_de": "Ein weiteres Journal. Dieselbe Handschrift. Aber {agent} bemerkt: Die Experimente sind ambitionierter. Die Ränder enthalten Skizzen unmöglicher Maschinen."}, "mutation": {"text_en": "The journal writes itself now. Pages fill as the party watches. The experiments described are the party's own. Documented before they happened.", "text_de": "Das Journal schreibt sich jetzt selbst. Seiten füllen sich, während der Trupp zusieht. Die beschriebenen Experimente sind die eigenen des Trupps. Dokumentiert, bevor sie stattfanden."}, "climax": {"text_en": "The last page of the journal contains one sentence: 'They made the right thing.' It is written in the future tense.", "text_de": "Die letzte Seite des Journals enthält einen Satz: »Sie haben das Richtige gemacht.« Er ist im Futur geschrieben."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_filament$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A filament. Thin as intention, strung between two posts that hold it with the delicacy of an experiment not yet concluded. It hums – not with current but with readiness. It is waiting to conduct.", "text_de": "Ein Filament. Dünn wie eine Absicht, gespannt zwischen zwei Pfosten, die es halten mit der Behutsamkeit eines noch nicht abgeschlossenen Experiments. Es summt – nicht mit Strom, sondern mit Bereitschaft. Es wartet darauf, zu leiten."}, "echo": {"text_en": "{agent} finds the filament again. Brighter. It has learned something between rooms – the hum is steadier, more purposeful. Something passed through it. It liked it.", "text_de": "{agent} findet das Filament wieder. Heller. Es hat etwas gelernt zwischen den Räumen – das Summen ist stetiger, zielgerichteter. Etwas ist hindurchgegangen. Es hat ihm gefallen."}, "mutation": {"text_en": "The filament has branched. A network now, strung between every surface, humming with the harmonics of connection. It conducts nothing the party sent. It is conducting itself.", "text_de": "Das Filament hat sich verzweigt. Ein Netzwerk jetzt, gespannt zwischen jeder Fläche, summend mit den Obertönen der Verbindung. Es leitet nichts, was der Trupp geschickt hat. Es leitet sich selbst."}, "climax": {"text_en": "The filament glows. Steady, warm, precise. It does not illuminate the room – it illuminates the pattern. The pattern is the party's route through the dungeon. The filament knew it before they walked it.", "text_de": "Das Filament glüht. Stetig, warm, präzise. Es erleuchtet nicht den Raum – es erleuchtet das Muster. Das Muster ist die Route des Trupps durch den Dungeon. Das Filament kannte sie, bevor sie sie gingen."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_scale_model$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A model on the workbench. Small, intricate, assembled from wire and crystal and something that looks like compressed light. It is a model of a machine that does not exist. The craftsmanship suggests it should.", "text_de": "Ein Modell auf der Werkbank. Klein, filigran, zusammengesetzt aus Draht und Kristall und etwas, das wie komprimiertes Licht aussieht. Es ist das Modell einer Maschine, die nicht existiert. Die Handwerkskunst legt nahe, dass sie es sollte."}, "echo": {"text_en": "{agent} examines the model. It has grown. Not in size – in detail. Components that were abstract are now precise. The model is refining itself.", "text_de": "{agent} untersucht das Modell. Es ist gewachsen. Nicht in der Größe – im Detail. Komponenten, die abstrakt waren, sind jetzt präzise. Das Modell verfeinert sich selbst."}, "mutation": {"text_en": "The model is larger than the workbench now. It has outgrown its frame. Parts of it extend beyond the table's edge, hovering in place as if scale were a suggestion it has decided to decline.", "text_de": "Das Modell ist jetzt größer als die Werkbank. Es ist über seinen Rahmen hinausgewachsen. Teile davon ragen über den Tischrand hinaus, schwebend, als wäre Maßstab ein Vorschlag, den es abzulehnen beschlossen hat."}, "climax": {"text_en": "The model is the room. The room is the model. The machine it described has been built – around you, with you inside it. The scale was always 1:1.", "text_de": "Das Modell ist der Raum. Der Raum ist das Modell. Die Maschine, die es beschrieb, wurde gebaut – um euch, mit euch darin. Der Maßstab war immer 1:1."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_alloy$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A sample of metal on the bench. Not a single element – a blend, still warm from the fusion. The surface shifts color when observed from different angles. The alloy has not decided what it wants to be.", "text_de": "Eine Metallprobe auf der Bank. Kein einzelnes Element – eine Legierung, noch warm von der Verschmelzung. Die Oberfläche wechselt die Farbe je nach Blickwinkel. Die Legierung hat noch nicht entschieden, was sie sein will."}, "echo": {"text_en": "{agent} picks up the alloy. It has settled – one color now, one texture. But it is warm in exactly the places where {agent}'s grip falls. It is accommodating.", "text_de": "{agent} hebt die Legierung auf. Sie hat sich beruhigt – eine Farbe jetzt, eine Textur. Aber sie ist genau dort warm, wo {agent}s Griff fällt. Sie fügt sich."}, "mutation": {"text_en": "The alloy has divided itself. Three pieces, each a different composition, each optimized for a property the original lacked: hardness, conductivity, resonance. It did not wait to be forged. It forged itself.", "text_de": "Die Legierung hat sich geteilt. Drei Stücke, jedes eine andere Zusammensetzung, jedes optimiert für eine Eigenschaft, die dem Original fehlte: Härte, Leitfähigkeit, Resonanz. Sie hat nicht gewartet, geschmiedet zu werden. Sie hat sich selbst geschmiedet."}, "climax": {"text_en": "The alloy is gone. In its place: a tool that fits no category in the workshop's index. It is made of everything it tried. The forge did not make this. The material did.", "text_de": "Die Legierung ist weg. An ihrer Stelle: ein Werkzeug, das in keine Kategorie des Werkstattverzeichnisses passt. Es besteht aus allem, was es versucht hat. Die Schmiede hat das nicht gemacht. Das Material schon."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($DQ$prometheus_flame$DQ$, $DQ$The Prometheus$DQ$, $JB${"discovery": {"text_en": "A flame. Small, contained in a glass crucible. It burns without fuel – not magical, but self-sustaining. The combustion feeds on its own product. It is a proof of concept for something that should not work.", "text_de": "Eine Flamme. Klein, in einem Glastiegel. Sie brennt ohne Brennstoff – nicht magisch, sondern selbsterhaltend. Die Verbrennung nährt sich von ihrem eigenen Produkt. Sie ist ein Machbarkeitsnachweis für etwas, das nicht funktionieren sollte."}, "echo": {"text_en": "{agent} passes the flame. It has changed color – responding to the party's proximity the way a forge responds to the bellows. It is not warming itself. It is warming to them.", "text_de": "{agent} passiert die Flamme. Sie hat ihre Farbe gewechselt – reagierend auf die Nähe des Trupps, wie eine Schmiede auf den Blasebalg reagiert. Sie wärmt nicht sich selbst. Sie erwärmt sich für sie."}, "mutation": {"text_en": "The crucible is cracked. The flame has outgrown it – not violently, but persistently. Glass cannot contain what the flame has become. It burns freestanding now, feeding on air that tastes of ambition.", "text_de": "Der Tiegel hat Risse. Die Flamme ist ihm entwachsen – nicht gewaltsam, aber beharrlich. Glas kann nicht enthalten, was die Flamme geworden ist. Sie brennt jetzt freistehend, genährt von Luft, die nach Ambition schmeckt."}, "climax": {"text_en": "The flame is the room's only light. It has consumed neither fuel nor air nor patience. It is the oldest fire in the workshop – the one that was stolen, and refused to go out.", "text_de": "Die Flamme ist das einzige Licht des Raums. Sie hat weder Brennstoff noch Luft noch Geduld verbraucht. Sie ist das älteste Feuer in der Werkstatt – das, das gestohlen wurde und sich weigerte zu erlöschen."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The threshold does not yield. It opens. Deliberately. Beyond it, the air is warm and charged with potential. Tools line the walls in arrangements that suggest use, not storage. The workshop has been expecting someone.$DQ$, $DQ$Die Schwelle gibt nicht nach. Sie öffnet sich. Absichtlich. Dahinter ist die Luft warm und geladen mit Potential. Werkzeuge säumen die Wände in Anordnungen, die Benutzung suggerieren, nicht Lagerung. Die Werkstatt hat jemanden erwartet.$DQ$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$Heat. Not the heat of fire – the heat of process. The air smells of ozone and possibility. Somewhere deeper, metal rings against metal. Not randomly. Rhythmically. A heartbeat made of industry.$DQ$, $DQ$Hitze. Nicht die Hitze von Feuer – die Hitze von Prozess. Die Luft riecht nach Ozon und Möglichkeit. Irgendwo tiefer klingt Metall gegen Metall. Nicht zufällig. Rhythmisch. Ein Herzschlag aus Industrie.$DQ$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The descent into the workshop begins with a question written on the lintel in a script older than the stone: 'What do you intend to make?' The party has no answer yet. The workshop will provide the materials for one.$DQ$, $DQ$Der Abstieg in die Werkstatt beginnt mit einer Frage, die am Türsturz steht, in einer Schrift, älter als der Stein: »Was beabsichtigt ihr herzustellen?« Der Trupp hat noch keine Antwort. Die Werkstatt wird die Materialien für eine liefern.$DQ$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$The first room is a catalogue of components. Not displayed – arranged. Each material in its place, each place chosen by a logic that makes no sense until you pick something up and feel where it wants to go. The workshop teaches through inventory.$DQ$, $DQ$Der erste Raum ist ein Katalog von Komponenten. Nicht ausgestellt – arrangiert. Jedes Material an seinem Platz, jeder Platz gewählt nach einer Logik, die keinen Sinn ergibt, bis man etwas aufnimmt und spürt, wohin es will. Die Werkstatt lehrt durch Inventar.$DQ$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($DQ$The Prometheus$DQ$, $DQ$A forge-glow illuminates the entrance. Not from a furnace – from the walls themselves. The workshop provides its own light, its own heat, its own purpose. All it lacks is hands. Yours will do.$DQ$, $DQ$Ein Schmiedeglühen beleuchtet den Eingang. Nicht von einem Ofen – von den Wänden selbst. Die Werkstatt liefert ihr eigenes Licht, ihre eigene Hitze, ihren eigenen Zweck. Alles, was ihr fehlt, sind Hände. Eure werden genügen.$DQ$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 0, $DQ$The forge is cold. Tools rest in their places. The workshop presents itself with clinical patience. Materials await hands. The fire has not yet been stolen.$DQ$, $DQ$Die Schmiede ist kalt. Werkzeuge ruhen an ihren Plätzen. Die Werkstatt präsentiert sich mit klinischer Geduld. Materialien warten auf Hände. Das Feuer wurde noch nicht gestohlen.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 1, $DQ$The forge warms. The first sparks have been struck. Components respond to proximity – not yet with intent, but with interest. The workshop is watching what the party does.$DQ$, $DQ$Die Schmiede erwärmt sich. Die ersten Funken wurden geschlagen. Komponenten reagieren auf Nähe – noch nicht mit Absicht, aber mit Interesse. Die Werkstatt beobachtet, was der Trupp tut.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 2, $DQ$The fire burns steady. The workshop has opened its deeper chambers. Materials levitate briefly before settling. The air tastes of ambition. Every surface is warm to the touch.$DQ$, $DQ$Das Feuer brennt gleichmäßig. Die Werkstatt hat ihre tieferen Kammern geöffnet. Materialien schweben kurz, bevor sie sich setzen. Die Luft schmeckt nach Ambition. Jede Oberfläche ist warm bei Berührung.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($DQ$The Prometheus$DQ$, 3, $DQ$White heat. The workshop is no longer subtle. Components arrange themselves without being touched. The forge-glow pulses in time with the party's breathing. The fire knows. The fire burns.$DQ$, $DQ$Weißglut. Die Werkstatt ist nicht mehr subtil. Komponenten ordnen sich an, ohne berührt zu werden. Das Schmiedeglühen pulsiert im Takt der Atmung des Trupps. Das Feuer weiß. Das Feuer brennt.$DQ$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
